export class McpPool {
  private servers: ConnectedServer[] = [];
  private toolIndex = new Map<string, ConnectedServer>();

  /** Connect to all enabled MCP servers from a config object. */
  async connectAll(configs: Record<string, McpServerConfig>, extraEnv?: Record<string, string>): Promise<void> {
    const entries = Object.entries(configs).filter(([, c]) => !c.disabled);
    const results = await Promise.allSettled(
      entries.map(([name, cfg]) => this.connectOne(name, cfg, extraEnv)),
    );
    for (let i = 0; i < results.length; i++) {
      if (results[i].status === "rejected") {
        console.warn(`[mcp-pool] failed to connect "${entries[i][0]}":`, (results[i] as PromiseRejectedResult).reason?.message ?? results[i]);
      }
    }
  }

  private async connectOne(name: string, cfg: McpServerConfig, extraEnv?: Record<string, string>): Promise<void> {
    const transport = new StdioClientTransport({
      command: cfg.command,
      args: cfg.args ?? [],
      env: { ...process.env, ...cfg.env, ...extraEnv } as Record<string, string>,
    });
    const client = new Client({ name: `bridge-pool-${name}`, version: "1.0.0" });
    await client.connect(transport);

    const { tools } = await client.listTools();
    const schemas: ToolSchema[] = (tools ?? []).map((t) => ({
      name: t.name,
      description: t.description,
      inputSchema: t.inputSchema as Record<string, unknown>,
      _server: name,
    }));

    const server: ConnectedServer = { name, client, transport, tools: schemas };
    this.servers.push(server);
    for (const t of schemas) {
      this.toolIndex.set(t.name, server);
    }
    console.log(`[mcp-pool] connected "${name}" — ${schemas.length} tools`);

