export async function handleTopicReview(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }
  await runPrompt(ctx, session, TOPIC_REVIEW_PROMPT, { kind: "meta" });
}


// ─── /refreshrouting ────────────────────────────────────────────────────────

const REFRESH_ROUTING_PROMPT =
  "請執行 NotebookLM routing table 刷新（v2 repr 格式）：\n" +
  `1. 依 \`ms-notebooklm-routing-builder\` skill 的流程：先 \`notebook_list\` 拿現況，讀既有 \`${MEMORY_DIR}/config/notebooklm-routing.json\`（如存在）做 diff。\n` +
  `2. 寫新檔前先備份到 \`${MEMORY_DIR}/config/notebooklm-routing.bak.<ts>.json\`（保留最近 5 份，舊的清掉）。\n` +
  "3. 對每本 notebook 跑 `notebook_query` 產出 repr 文字（一段 100-300 字的主題描述，涵蓋核心術語、人名、專有名詞，供 embedding 向量化用）。\n" +
  "4. 合併規則：\n" +
  "   - 新 notebook → append 新 entry（notebook_id, title, repr, strategy: 'primary'）。\n" +
  "   - 既有 notebook → 只更新 repr / last_refreshed；strategy / strategy_notes / manual_overrides 絕不覆蓋。\n" +
  "   - 從 NotebookLM 消失的 notebook → 標 `\"removed\": true` 而非硬刪。\n" +
  "   - `multi_match_rules` 原樣保留，不碰。\n" +
  "5. 最後回報：新增/刪除/更新了哪些 notebook、repr 差異摘要、備份檔路徑。\n" +
  "整個過程用繁體中文摘要，不要貼完整 JSON。";

export async function handleRefreshRouting(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }
  await runPrompt(ctx, session, REFRESH_ROUTING_PROMPT, { kind: "meta" });
}

// ─── /wikisync ──────────────────────────────────────────────────────────────

const WIKISYNC_PROMPT =
  `請執行 wiki sync（依 ms-wiki-knowledge-base skill 的 wikisync 邏輯）：\n` +
  `0. 若 ${MEMORY_DIR}/wiki/ 目錄不存在，先建立 wiki/、wiki/concepts/、wiki/references/、wiki/lessons/、wiki/queries/ 並寫一份空 index.md（參考 SCHEMA.md 格式）。\n` +
  `1. 讀 ${MEMORY_DIR}/wiki/index.md 取得現有 wiki 頁面列表。\n` +
  `2. 呼叫 list_facts({ query: '', tail: 0 }) 或讀 topics.json 取得所有 topic 名稱。\n` +
  `3. 對每個 topic shard（≥5 facts 且 index.md 中無對應 wiki page）：\n` +

