import { copyFileSync, cpSync, existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";

const globalRoot = process.platform === "win32"
  ? path.join(process.env.APPDATA || path.join(os.homedir(), "AppData", "Roaming"), "npm", "node_modules")
  : path.join(path.dirname(process.execPath), "..", "lib", "node_modules");

const sourceDir = path.join(globalRoot, "notebooklm-mcp-server");
const targetDir = process.env.LOCAL_NOTEBOOKLM_MCP_DIR || "F:\\AI_Codex\\notebooklm-mcp-server";
const codexConfig = process.env.CODEX_CONFIG_PATH || path.join(os.homedir(), ".codex", "config.toml");
const entrypoint = path.join(targetDir, "dist", "index.js");

if (!existsSync(sourceDir)) {
  throw new Error(`Global notebooklm-mcp-server not found: ${sourceDir}`);
}
if (existsSync(targetDir)) {
  throw new Error(`Target already exists, refusing to overwrite: ${targetDir}`);
}

mkdirSync(targetDir, { recursive: true });
cpSync(sourceDir, targetDir, { recursive: true });

const packageJsonPath = path.join(targetDir, "package.json");
const packageJson = JSON.parse(readFileSync(packageJsonPath, "utf8"));
packageJson.name = "notebooklm-mcp-server-local";
packageJson.private = true;
writeFileSync(packageJsonPath, `${JSON.stringify(packageJson, null, 2)}\n`, "utf8");

const localReadme = [
  "# Local NotebookLM MCP Server",
  "",
  "Vendored local MCP server copied from global notebooklm-mcp-server@3.0.7 on 2026-06-16.",
  "",
  "Codex is configured to launch this copy directly:",
  "",
  "```toml",
  "[mcp_servers.notebooklm]",
  'command = "node"',
  `args = ["${entrypoint.replaceAll("\\", "\\\\")}", "server"]`,
  "```",
  "",
  "Local changes currently include the NotebookLM Video Overview RPC payload fix and studio_poll video media_url extraction fix.",
  "",
].join("\n");
writeFileSync(path.join(targetDir, "README.local.md"), localReadme, "utf8");

const configText = readFileSync(codexConfig, "utf8");
const backupPath = `${codexConfig}.bak-local-notebooklm-${new Date().toISOString().replace(/[:.]/g, "-")}`;
copyFileSync(codexConfig, backupPath);

const notebooklmBlock = [
  "[mcp_servers.notebooklm]",
  'command = "node"',
  `args = ["${entrypoint.replaceAll("\\", "\\\\")}", "server"]`,
].join("\n");

const blockPattern = /\[mcp_servers\.notebooklm\]\r?\ncommand = "[^"]*"\r?\nargs = \[[^\]]*\]/;
const nextConfig = blockPattern.test(configText)
  ? configText.replace(blockPattern, notebooklmBlock)
  : `${configText.trimEnd()}\n\n${notebooklmBlock}\n`;

writeFileSync(codexConfig, nextConfig, "utf8");

console.log(`created: ${targetDir}`);
console.log(`updated: ${codexConfig}`);
console.log(`backup: ${backupPath}`);
